+  int r;
+  bool raised = false;
+  AL::ALError err;
+
+  ALCriticalSectionAllowThreadsPython section;
+  try
+  {
+    r  = fProxy->genericPCall(strMethod, resultParam);
+  }
+  catch(AL::ALError& e)
+  {
+    raised = true;
+    err = e;
+  }
+
+  if(raised)
+    throw(err);
+  return r;
+}
