+bool Timeline::loadFromFile(std::string fileName)
+{
+  std::string errorMsg;
+  boost::shared_ptr<AL::XmlDocument> xmlFile = AL::XmlDocument::loadFromXmlFile(fileName, NULL, &errorMsg);
