+  TransitionTest* toS2 = new TransitionTest(s2);
+  TransitionTest* toS3 = new TransitionTest(s3);
+
+  s1->addTransition(toS2);
+  s2->addTransition(toS3);
+
+  sm.addState(s1);
+  sm.addState(s2);
+  sm.addState(s3);
+
+  sm.setInitialState(s1);
+  sm.setFinalState(s2);
